const body = $input.first().json;
const status = body.status ?? body.type ?? 'UNKNOWN';
const service = body.service?.name ?? body.serviceName ?? 'sergeant-api';
const env = body.environment?.name ?? body.environmentName ?? 'production';
const branch = body.deployment?.meta?.branch ?? body.branch ?? '—';
const commitMsg = body.deployment?.meta?.commitMessage ?? body.commitMessage ?? '—';
const commitHash = (body.deployment?.meta?.commitHash ?? body.commitHash ?? '').slice(0, 7);
const url = body.deployment?.url ?? body.deploymentUrl ?? '';
const duration = body.buildDuration ? `${Math.round(body.buildDuration / 1000)}s` : '—';
const ok = ['SUCCESS', 'DEPLOYED', 'ACTIVE'].includes(status.toUpperCase());
return [{ json: { status, service, env, branch, commitMsg, commitHash, url, duration, ok } }];
